class SimplePinController:
    def __init__(self, pin_no=2, active_high=True):
        self.pin_no = pin_no
        self.active_high = active_high
        self.pin = machine.Pin(pin_no, machine.Pin.OUT)
        self.turn_off()

    def _write(self, on):
        val = 1 if on else 0
        if not self.active_high:
            val ^= 1
        self.pin.value(val)

    def turn_on(self):
        self._write(True)

    def turn_off(self):
        self._write(False)

    def toggle(self):
        self._write(not self.is_on())

    def is_on(self):
        v = self.pin.value()
        if not self.active_high:
            v ^= 1
        return bool(v)


