    if not lines or " " not in lines[0]:
        raise WebSocketError("Invalid HTTP request line")

    req_line = lines[0]
    parts = req_line.split(" ")
    method = parts[0].upper()
    path = parts[1] if len(parts) > 1 else "/"

    headers = {}
